module png_paeth_predictor(
    input [7:0] current_pixel,
    input [7:0] left_pixel,
    input [7:0] above_pixel,
    input [7:0] above_left_pixel,
    output reg [7:0] predicted_pixel
);

    function [7:0] paeth_predictor;
        input [7:0] a; // above
        input [7:0] b; // left
        input [7:0] c; // above-left
        reg [7:0] obf_p;
        reg [7:0] pa;
        reg [7:0] pb;
        reg [7:0] pc;
        begin
            obf_p = a + b - c;
            pa = (obf_p > a) ? obf_p - a : a - obf_p;
            pb = (obf_p > b) ? obf_p - b : b - obf_p;
            pc = (obf_p > c) ? obf_p - c : c - obf_p;
            if (pa <= pb && pa <= pc) 
                paeth_predictor = a;
            else if (pb <= pc) 
                paeth_predictor = b;
            else 
                paeth_predictor = c;
        end
    endfunction

    always @(*) begin
        predicted_pixel = paeth_predictor(above_pixel, left_pixel, above_left_pixel);
    end
endmodule
